using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

namespace Azure.ResourceManager
{
    internal sealed class ResponseErrorConverter : JsonConverter<ResponseError>
    {
        internal static readonly JsonSerializerOptions Options = new() { Converters = { new ResponseErrorConverter() } };
        internal static readonly JsonTypeInfo<ResponseError> TypeInfo = (JsonTypeInfo<ResponseError>)Options.GetTypeInfo(typeof(ResponseError));

        public override ResponseError Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            using var document = JsonDocument.ParseValue(ref reader);
            var element = document.RootElement;

            string code = null;
            string message = null;

            if (element.TryGetProperty("code", out var codeProp))
            {
                code = codeProp.GetString();
            }
            if (element.TryGetProperty("message", out var messageProp))
            {
                message = messageProp.GetString();
            }

            return new ResponseError(code, message);
        }

        public override void Write(Utf8JsonWriter writer, ResponseError value, JsonSerializerOptions options)
        {
            writer.WriteStartObject();
            if (value.Code != null)
            {
                writer.WriteString("code", value.Code);
            }
            if (value.Message != null)
            {
                writer.WriteString("message", value.Message);
            }
            writer.WriteEndObject();
        }
    }
}

